// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（看向李杰）你⋯⋯要跟我們一起走嗎？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰沉默地看著眼前這對母子三人。母親膝蓋上的傷口還在滲血，兩個孩子緊緊抓著她的手，眼神中滿是恐懼與不安。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）跟著他們去亡者峽谷？一個受傷的母親，兩個年幼的孩子⋯⋯在這種鬼地方，這只會成為拖累。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想起剛才在車站內找到的地圖。三條路線清晰地標示著——北邊的「亡者峽谷」、南邊的「迷霧之森」、還有西邊的「銀月湖」。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）我們才剛認識不到幾個小時，說到底只是陌生人。在這種隨時可能喪命的情況下，帶著他們只會讓我自己也陷入危險。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰深吸一口氣，做出了決定。他從口袋裡掏出那張泛黃的地圖，展開給那位母親看。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（平靜地說）這是我在車站裡找到的地圖。沿著鐵軌走確實能到亡者峽谷，但那條路完全暴露在外，沒有任何遮蔽。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（抬起頭，眼神中閃過一絲希望）那⋯⋯還有別的路嗎？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（指著地圖）森林裡有一條主要路徑，也通往北方的亡者峽谷。走那條路應該比沿著鐵軌安全一些，至少有樹木遮蔽。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（感激地點頭）謝謝你⋯⋯真的謝謝你。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（收起地圖）不過我不會跟你們一起走。我有自己的打算。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "母親愣了一下，但很快理解了他的意思。她沒有表現出失望或責怪，只是輕輕點了點頭。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（輕聲）我明白。謝謝你告訴我們這些⋯⋯已經幫了我們很多了。" },
    { characterId: CharacterId.KobayashiHina, character: "懂事姐姐", dialogue: "（拉著媽媽的手，小聲問）大哥哥不跟我們一起走嗎？" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（溫柔地摸摸女兒的頭）大哥哥有自己的事情要做。我們要自己去找爸爸，對不對？" },
    { characterId: CharacterId.KobayashiHina, character: "懂事姐姐", dialogue: "（點點頭，看向李杰）那⋯⋯大哥哥你要小心喔。" },
    { characterId: CharacterId.KobayashiShota, character: "天真弟弟", dialogue: "（也揮揮手）拜拜，大哥哥。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（微微點頭）你們也是。小心一點。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "母親牽起兩個孩子的手，朝著森林的北方走去。她的背影在紫月的光輝下顯得有些單薄，但依然挺直。兩個小小的身影緊緊跟在她身旁。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很快，他們的身影就消失在森林的黑暗之中。月台上只剩下李杰一個人。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（低聲自語）祝你們好運。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉過身，看向地圖上標示的南方——迷霧之森。雖然名字聽起來不太吉利，但至少不像「亡者峽谷」那樣直白地充滿死亡氣息。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）獨自一人，行動會更自由。沒有拖累，也不用為別人的安危負責。在這種地方，這才是最理性的選擇。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他握緊手中的鏽劍，沿著月台走向南側的出口。那裡有一條被雜草覆蓋的小徑，隱約能看出曾經有人走過的痕跡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰踏上小徑，身後「幽冥之都」的荒廢車站漸漸遠去。兩輪紫月依舊懸在天空，將他的影子拉得很長。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "森林裡的空氣冰冷而潮濕，帶著一股腐葉和潮濕泥土的氣味。頭頂茂密的樹冠幾乎遮住了所有光線，只有零星的紫色月光透過縫隙灑下來，在地面上形成斑駁的光影。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小徑彎彎曲曲，時而被倒下的樹幹擋住，時而被蔓生的藤蔓遮蓋。李杰小心翼翼地撥開擋路的枝葉，一步一步向前。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這條路很久沒人走過了⋯⋯但至少還能辨認出方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "森林裡寂靜得可怕。沒有蟲鳴，沒有鳥叫，甚至連風吹樹葉的聲音都顯得空洞而遙遠。只有李杰自己的腳步聲，踩在落葉上發出的「沙沙」聲響。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走了一段時間後，周圍的環境開始起了變化。空氣中的濕度明顯增加，一股淡淡的霧氣開始在林間飄散。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（停下腳步，警覺地）霧？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "霧氣並不濃，只是像輕紗一樣籠罩在樹林間，讓視線變得有些模糊。但這足以讓李杰提高警覺。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）迷霧之森⋯⋯看來名副其實。得更小心了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他繼續前進。霧氣越來越濃，從淡淡的薄霧逐漸變成讓人難以看清五公尺外的白色霧牆。樹木的輪廓變得模糊，遠處的景象完全消失在白茫茫的霧氣中。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又走了一段時間，李杰突然停下腳步。前方，小徑似乎到了盡頭。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（皺眉）這是⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走近一看，發現自己來到了一個四叉路口。小徑在這裡分成了四條路——前方、左側、右側，還有來時的路。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "每條路都被濃霧籠罩，看不出有什麼區別。李杰連忙從口袋裡掏出地圖，想確認該走哪個方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但當他攤開地圖時，心中一沉。地圖只標示到車站附近的大致路線，對於森林深處的細節完全沒有繪製。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（低聲）該死⋯⋯地圖沒有標示這裡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他環顧四周，試圖從環境中找出一些線索。但濃霧遮蔽了一切，三條路看起來都一模一樣。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）該往哪走？隨便選一條嗎？萬一走錯了⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在他猶豫不決時，左側的霧氣中突然出現了動靜。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一個黑色的影子，緩緩從霧中浮現。由於霧氣太濃，李杰完全無法看清那是什麼——只能看到一個純粹的黑色輪廓，像是被剪影一樣。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個影子的形狀看起來像是人形，但在迷霧的扭曲下，顯得格外詭異和不真實。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心，警覺）什麼東西？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰的本能告訴他——這不是什麼友善的存在。那個黑影散發出的氣息，讓他全身的汗毛都豎了起來。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）不對勁⋯⋯得躲起來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他迅速環顧四周，發現路口旁有一叢茂密的灌木叢。沒有多想，他立刻低身鑽了進去，整個人蜷縮在枝葉的遮蔽之下。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鏽劍緊握在手中，他屏住呼吸，透過枝葉的縫隙注視著那個黑影。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑影越來越近。霧氣逐漸散開，那個輪廓也變得越來越清晰。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一個男人。他穿著一身黑色的衣服，帽簷壓得極低，遮住了大半張臉。右手握著一把黑色的劍，劍身細長，在紫月的微光下泛著冷冽的光芒。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心，震驚）那把劍⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "男人的步伐很慢，但很穩。他似乎對這片森林非常熟悉，即使在濃霧中也沒有任何遲疑。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "當他走到路口時，李杰終於看清了他的側臉——雖然只有一瞬間，但那張臉讓李杰感到一股說不出的寒意。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）是他⋯⋯在「寂海」站時，從列車上看到走向森林的人影⋯⋯就是這個人！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "男人在路口停頓了片刻，像是在確認什麼。李杰屏住呼吸，不敢發出任何聲音。他甚至能聽到自己的心跳聲在胸腔中迴盪。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "幾秒後，男人繼續往右側的小徑走去，緩緩穿過路口。他的身影逐漸被霧氣吞沒，腳步聲也漸漸遠去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰依然沒有動，他在灌木叢中又等了好幾分鐘，確認那個男人真的離開了，才小心翼翼地鑽出來。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（低聲，擦了擦額頭的冷汗）好險⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起身，拍了拍身上的落葉。剛才那個男人散發出的氣息，讓他確信一件事——絕對不能跟那個人對上。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）那把黑劍⋯⋯絕對不是裝飾品。那個人很危險。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看向三條路。左邊是男人來的方向，右邊是男人離開的方向。而前方，則是一條未知的路。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）不能走右邊，萬一追上那個人就糟了。左邊是回到車站的方向⋯⋯看來只能往前走了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸一口氣，握緊手中的鏽劍，朝著前方的小徑走去。霧氣依然濃厚，但至少，他避開了那個危險的黑衣男。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這條小徑和之前的路一樣寬敞，看起來也是主要路線之一。霧氣在這裡顯得更濃，幾乎無法看清前方三公尺外的景象。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰一步一步小心地前進，每一步都格外謹慎。在這種環境下，任何一個不注意都可能踩空或撞上什麼東西。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "時間變得難以估計。在這片永恆的霧氣中，他不知道走了多久。可能是十分鐘，也可能是半小時。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳下的路面開始變得平坦起來，樹木也逐漸稀疏。霧氣雖然依舊濃厚，但前方似乎出現了一片較為開闊的空間。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）前面有什麼？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他繼續向前，穿過最後幾棵樹。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後，他停下了腳步。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在霧氣籠罩的空地中央，矗立著一座木造房屋。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（驚訝）房子？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一棟單層的木屋，結構簡樸卻完整，看起來保養得相當不錯。木板牆面雖然有些斑駁，但沒有腐朽的跡象。屋頂覆蓋著深色的瓦片，窗戶緊閉，門前還有一個小小的木製台階。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在這片荒涼而詭異的森林深處，這座房子的存在顯得格外突兀。它就像一個不屬於這個世界的異物，靜靜地立在霧氣之中。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這種地方⋯⋯怎麼會有房子？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他握緊手中的鏽劍，警戒地盯著那座木屋。窗戶是黑的，看不出裡面有沒有燈光。門緊閉著，看不出有人進出的痕跡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但那完好的結構，讓人無法判斷這裡是否還有人居住。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）先觀察一下⋯⋯如果有危險，立刻撤退。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他小心翼翼地靠近那座木屋，每一步都格外謹慎。濃霧在他周圍流動，彷彿在低語著什麼警告。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩輪紫月的光芒透過霧氣灑下，將木屋染成一片詭異的紫黑色。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰站在木屋前，注視著那扇緊閉的門。他不知道門後是什麼——是庇護所，還是另一個陷阱。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但在這片充滿未知的森林裡，這座房子，可能是他唯一的選擇。" },
];
